Table.items:
{
                       path: '/DraftPurchaseRequisitions',
                       filters: [{ path: 'status', operator: 'EQ', value1: 'DRAFT' }],
                       parameters: {
                           $expand: 'items($expand=material,vendor)',
                           $orderby: 'modifiedAt desc'
                       }
                   }

Text.text:
{
                                path: 'modifiedAt',
                                type: 'sap.ui.model.type.DateTimeOffset',
                                formatOptions: { pattern: 'MMM dd, yyyy, hh:mm a' }
                            }
